def calculate_rouge(ref, pred):
    scorer = rouge_scorer.RougeScorer(['rouge1', 'rougeL'], use_stemmer=True)
    scores = scorer.score(ref, pred)
    return scores['rouge1'].fmeasure, scores['rougeL'].fmeasure

def calculate_bleu(ref, pred):
    smoothie = SmoothingFunction().method4
    return sentence_bleu([ref.split()], pred.split(), smoothing_function=smoothie)

def compression_ratio(original, summary):
    return len(summary.split()) / len(original.split())

rouge1_scores, rougeL_scores, bleu_scores, comp_ratios, times = [], [], [], [], []

for s in samples:
    start = time.time()
    ref, pred = s["text"], s["summary"]

    # Simulate summarization process delay
    time.sleep(0.2)

    r1, rL = calculate_rouge(ref, pred)
    bleu = calculate_bleu(ref, pred)
    comp = compression_ratio(ref, pred)
    elapsed = time.time() - start

    rouge1_scores.append(r1)
    rougeL_scores.append(rL)
    bleu_scores.append(bleu)
    comp_ratios.append(comp)
    times.append(elapsed)

x_labels = [f"Doc {i+1}" for i in range(len(samples))]

plt.figure(figsize=(10, 6))
plt.plot(x_labels, rouge1_scores, marker='o', label='ROUGE-1')
plt.plot(x_labels, rougeL_scores, marker='o', label='ROUGE-L')
plt.plot(x_labels, bleu_scores, marker='o', label='BLEU')
plt.title("Summarization Accuracy Metrics")
plt.xlabel("Test Documents")
plt.ylabel("Score")
plt.ylim(0, 1)
plt.legend()
plt.grid(True)
plt.show()

plt.figure(figsize=(10, 5))
plt.bar(x_labels, comp_ratios, color='skyblue')
plt.title("Compression Ratio (Summary Length / Original Length)")
plt.xlabel("Test Documents")
plt.ylabel("Compression Ratio")
plt.grid(axis='y')
plt.show()

plt.figure(figsize=(10, 5))
plt.bar(x_labels, times, color='orange')
plt.title("Summarization Response Time")
plt.xlabel("Test Documents")
plt.ylabel("Seconds")
plt.grid(axis='y')
plt.show()

print("Metrics calculated and visualized successfully!")
